package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.*;
import java.util.*;

import org.junit.jupiter.api.Test;

class $Gson$TypesTest {

  @Test
  void testGetCollectionElementType_withParameterizedType() throws Exception {
    // Create a parameterized type representing Collection<String>
    ParameterizedType collectionStringType = new ParameterizedType() {
      @Override
      public Type[] getActualTypeArguments() {
        return new Type[] { String.class };
      }

      @Override
      public Type getRawType() {
        return Collection.class;
      }

      @Override
      public Type getOwnerType() {
        return null;
      }
    };

    // Mock getSupertype to return our parameterized type
    $Gson$Types spyTypes = spy($Gson$Types.class);
    // Use reflection to access private static getSupertype method
    Method getSupertypeMethod = $Gson$Types.class.getDeclaredMethod("getSupertype", Type.class, Class.class, Class.class);
    getSupertypeMethod.setAccessible(true);

    // Instead of spying (class is final with private constructor), we will use reflection to call getCollectionElementType directly
    // But getCollectionElementType calls private static getSupertype inside, so we need to test with a real context type that returns a ParameterizedType

    // Use a concrete class extending Collection<String> to produce a parameterized supertype
    class StringList extends ArrayList<String> {}

    Type elementType = $Gson$Types.getCollectionElementType(StringList.class, StringList.class);
    assertEquals(String.class, elementType);
  }

  @Test
  void testGetCollectionElementType_withRawCollection() {
    // Use raw collection type (no generics)
    Type elementType = $Gson$Types.getCollectionElementType(Collection.class, Collection.class);
    assertEquals(Object.class, elementType);
  }

  @Test
  void testGetCollectionElementType_withNonCollectionSupertype() {
    // Use a class that does not extend Collection (e.g. String)
    // The method getSupertype returns Object.class or null, so elementType should be Object.class
    Type elementType = $Gson$Types.getCollectionElementType(String.class, String.class);
    assertEquals(Object.class, elementType);
  }
}
